import{_ as a,c as t,a as o,o as r}from"./app.80edbbb0.js";const p=JSON.parse('{"title":"The Beeminder Philosophy","description":"","frontmatter":{},"headers":[{"level":2,"title":"Akrasia: the problem Beeminder solves","slug":"akrasia-the-problem-beeminder-solves"},{"level":2,"title":"A commitment device","slug":"a-commitment-device"},{"level":2,"title":"Why money","slug":"why-money"},{"level":2,"title":"The akrasia horizon","slug":"the-akrasia-horizon"},{"level":2,"title":"The data is the point","slug":"the-data-is-the-point"},{"level":2,"title":"Further reading","slug":"further-reading"}],"relativePath":"philosophy.md"}'),n={name:"philosophy.md"};function i(s,e,h,l,d,m){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="the-beeminder-philosophy" tabindex="-1">The Beeminder Philosophy <a class="header-anchor" href="#the-beeminder-philosophy" aria-hidden="true">#</a></h1><p>Beeminder works by breaking down your long-term goal and turning it into concrete day-to-day actions with associated deadlines. These deadlines, and the monetary sting they threaten, serve to take a small part of the price you&#39;d pay by not achieving your goal and bring it into the present, allowing your long-term goal to influence your day-to-day behavior.</p><h2 id="akrasia-the-problem-beeminder-solves" tabindex="-1">Akrasia: the problem Beeminder solves <a class="header-anchor" href="#akrasia-the-problem-beeminder-solves" aria-hidden="true">#</a></h2><p><a href="https://blog.beeminder.com/akrasia/" target="_blank" rel="noopener noreferrer">Akrasia</a> is the ancient Greek word for acting against your own better judgment: knowing what you want to do and doing something else anyway. You mean to write every day, exercise a few times a week, or stop doomscrolling at midnight, but in the moment the long-term payoff feels abstract and the temptation feels real. The future you who benefits from the good habit has no vote in the decision the present you is making.</p><p>Almost everyone has goals they keep failing at this way, and the failure usually isn&#39;t about not knowing what to do or not wanting it badly enough. It&#39;s that the costs and rewards are spread out over time in a way that makes the wrong choice locally rational. Beeminder is built on the premise that this is a structural problem rather than a character flaw, and that the fix is to change the structure instead of trying harder.</p><h2 id="a-commitment-device" tabindex="-1">A commitment device <a class="header-anchor" href="#a-commitment-device" aria-hidden="true">#</a></h2><p>The tool Beeminder reaches for is a <a href="https://en.wikipedia.org/wiki/Commitment_device" target="_blank" rel="noopener noreferrer">commitment device</a>: a way of voluntarily restricting your own future choices so the version of you who shows up tomorrow can&#39;t easily weasel out. The classic example is Odysseus tying himself to the mast. He bound his future self in advance because he knew willpower alone wouldn&#39;t survive the song of the sirens.</p><p>Beeminder&#39;s mast is a pledge of real money. You commit to a measurable rate of progress, and if you go off track, Beeminder charges you. That turns a vague, deferred consequence (&quot;someday I&#39;ll regret not learning the guitar&quot;) into a sharp, immediate one (&quot;I owe $5 today&quot;). The point isn&#39;t the money itself. It&#39;s that a concrete cost <em>now</em> is something your present self actually responds to, in a way distant consequences never quite manage.</p><h2 id="why-money" tabindex="-1">Why money <a class="header-anchor" href="#why-money" aria-hidden="true">#</a></h2><p>The pledge works because losing money stings more than the same gain would please, a quirk of human psychology called <a href="https://en.wikipedia.org/wiki/Loss_aversion" target="_blank" rel="noopener noreferrer">loss aversion</a>. A small amount on the line, payable today, can outweigh a much larger but distant benefit, which is exactly the leverage you need to pull a long-term goal into the present.</p><p>It also escalates. After each derailment the pledge climbs a schedule ($0 \u2192 $5 \u2192 $10 \u2192 $30 \u2192 \u2026), so if one amount isn&#39;t enough to change your behavior, the next one will be. The aim is to find the smallest stake that actually works for you. For the full mechanics, see <a href="https://www.beeminder.com/money" target="_blank" rel="noopener noreferrer">how the money works</a>. And Beeminder <em>wants</em> you to keep your money: the charge is a backstop that gives the commitment its teeth, not a way for the company to make money off you.</p><h2 id="the-akrasia-horizon" tabindex="-1">The akrasia horizon <a class="header-anchor" href="#the-akrasia-horizon" aria-hidden="true">#</a></h2><p>A commitment device is only as good as your inability to wriggle out of it at the last second. So when you change a Beeminder goal, say by dialing the rate down, the change doesn&#39;t take effect for about a week. This delay is the <a href="https://help.beeminder.com/article/82-the-akrasia-horizon" target="_blank" rel="noopener noreferrer">akrasia horizon</a>. You can always make a goal <em>easier</em>, just never starting now; the change lands a week out, on the far side of the temptation you&#39;re feeling today.</p><p>This is what keeps the bright red line honest. In a moment of weakness, the only lever you have is to do the thing or pay the pledge. Loosening the goal is a decision your calmer, week-ago self gets to make, not your akratic present self.</p><h2 id="the-data-is-the-point" tabindex="-1">The data is the point <a class="header-anchor" href="#the-data-is-the-point" aria-hidden="true">#</a></h2><p>Beeminder is also a quantified-self tool. To enforce a commitment it has to measure your progress, and that measurement turns out to be useful on its own. Watching the datapoints pile up against your bright red line shows you what&#39;s actually happening instead of what you vaguely assume is happening, and that feedback often changes behavior before any money is at risk. See <a href="https://blog.beeminder.com/qs/" target="_blank" rel="noopener noreferrer">Beeminder as a self-tracking tool</a> for more on this angle.</p><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-hidden="true">#</a></h2><ul><li><a href="https://blog.beeminder.com/schelling/" target="_blank" rel="noopener noreferrer">Schelling Fences on Slippery Slopes</a> \u2014 the logic of drawing a bright line and refusing to cross it</li><li><a href="https://forum.beeminder.com/t/holiday-reading-beeminders-philosophy/7563" target="_blank" rel="noopener noreferrer">Holiday reading: Beeminder&#39;s philosophy</a> \u2014 a forum collection of the foundational posts</li><li><a href="https://blog.beeminder.com/akrasia/" target="_blank" rel="noopener noreferrer">Akrasia</a> \xB7 <a href="https://en.wikipedia.org/wiki/Commitment_device" target="_blank" rel="noopener noreferrer">Commitment device</a> \xB7 <a href="https://en.wikipedia.org/wiki/Loss_aversion" target="_blank" rel="noopener noreferrer">Loss aversion</a> \u2014 the underlying ideas</li><li><a href="./what-is-beeminder.html">What Is Beeminder?</a> \xB7 <a href="https://blog.beeminder.com/glossary/" target="_blank" rel="noopener noreferrer">Glossary</a> \u2014 the concepts and vocabulary in practice</li></ul>',18)])])}var u=a(n,[["render",i]]);export{p as __pageData,u as default};
